_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


ret.r = GetBlur3(vUv).r*0.6*(1-GetBlur1(vUv).r/2);
ret.r = max(ret.r,GetPixel(vUv).r*0.);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
dz.x = 2.0*GetBlur1(vUv+hor*gk).g-2.0*GetBlur1(vUv-hor*gk).g;
dz.y = 2.0*GetBlur1(vUv+ver*gk).g-2.0*GetBlur1(vUv-ver*gk).g;
dz *= GetBlur1(vUv).g > 0.04;
dz *= max(1,GetBlur2(vUv).g*8);

screen = vec3 ((vUv-0.5)*uAspect.xy+dz*0.25,1);
rs = project(); float lrs = length(rs.xy);
gmask = sat (1-.1*lrs) * (rs.z>0);
gmask *= sat (2-10*min(abs(rs.x),abs(rs.y)));
float gm0 = gmask;
uv2 = (rs)*0.15/(1+lrs*0.25);
//uv2 += vec2(0,q30)* (abs(uv2.x) < 3.0/4/64);

rip = texture(sampler_noise_lq,uv2*32*texture(sampler_pw_noise_lq,uv2));
gnd1 = tile(uv2);
gnd2 = tile(uv2+0.0002*vec2(q17,q18));
gmask = sat (gmask*3-2*dot(gnd1,gnd1));
gnd  = sat(gnd1 + -lum(gnd1-gnd2)*3);
float zblend = sat(abo-lrs/8);
smoke = 0.06*noise3(uv2-tstars*4).xy *zblend;

stars = 0; smask = 0;
uv4 = uv2*.1 +tstars*vec2(1,0.02) + 0.01*gnd;
smask = texture(sampler_pw_noise_lq,uv4)>.8;
stars = 1/length(abs(fract(uv4*256+ rip*0.1)-.5))*smask;

uv4 = uv2*.1 +tstars*vec2(0.02,1) + 0.01*gnd;
//uv4 = uv4.yx;
smask = texture(sampler_pw_noise_lq,uv4)>.8;
//stars += 1/length(abs(fract(uv4*256+ rip*0.1)-.5))*smask;

ret.b += (1-vUv.y)*0.2;
ret += gnd*gmask*(.15+stars*stars*0.01)*abo;

// Dioden
uv4 = uv0+dz*0.05;
vec3 dio = max(1.5*max(GetPixel(uv4).r,GetBlur1(uv4).r),GetBlur3(uv4).r);
ret += col(dio)*q3;

// Spiegelung
vec2 dref = rip.xy*0.018;
vec2 uvm = uv4-dref;
vec3 mirr = GetBlur1(uvm).b;
ret += gmask*abo * (uv0.y < 0.99)* (uv0.y > 0.01)* col(mirr)*(1+gnd) ;

//smoke
ret += smoke.x*q19;

//orb
uv1 = ((uv0-0.5)-vec2(q15,-q16))*uAspect.xy+dz*0.2;
ret += 0.00015/pow(length(uv1),2)*audioHigh;
uv1 = ((uv0-0.5)-vec2(q5,-q6))*uAspect.xy+rip*.02;
ret += 0.0007/pow(length(uv1),2)*abo*audioHigh*gnd*gmask;


//Glas
float refl = GetBlur1(uv0+dz*0.25).g/2;
ret += refl*(1+roam_cos);

//back light
float bl = 0;
uv1 = ((uv0-0.5)-rs*0-vec2(q1,-q2))*uAspect.xy+dz*4;
bl += .08/length(uv1)*sat(1-gm0);;
uv1 = ((uv0-0.5)-rs*0-vec2(q10,-q12))*uAspect.xy+gnd*0.1+dz*2+rip*.0;
bl += pow(.12/length(uv1),2)*gmask;

ret += q31*bl*(1+audioMidSmooth/2)*sat(1-smoke.x*32*rand_preset.x)*roam_cos;

ret = 1-exp(-ret*1.9);

  fragColor = ret;
}
